/** Text formatting helpers. */

export function formatTitle(title: string, limit = 60): string {
  const trimmed = title.trim();
  if (trimmed.length <= limit) {
    return trimmed;
  }
  return `${trimmed.slice(0, limit - 1)}\u2026`;
